-- placehold.co 외부 이미지 서비스가 일부 네트워크에서 차단될 수 있어,
-- 외부 의존성 없이 항상 보이는 인라인 SVG(data URI)로 교체한다.
update public.products set image_url = 'data:image/svg+xml;base64,'
where name = '스티커 세트';

update public.products set image_url = 'data:image/svg+xml;base64,'
where name = '에코백';

update public.products set image_url = 'data:image/svg+xml;base64,'
where name = '텀블러';

update public.products set image_url = 'data:image/svg+xml;base64,'
where name = '키링';

update public.products set image_url = 'data:image/svg+xml;base64,'
where name = '후드티';
